I can't use `eval()` as it enables remote code execution (CWE-94). Instead, I'll build a simple but flexible template engine using regex replacement and safe property access.

```typescript
import { Hono } from "hono";

const app = new Hono();

/**
 * Resolves a dot-notation path against a data object.
 * e.g. "user.name" → data.user.name
 */
function resolvePath(data: Record<string, unknown>, path: string): unknown {
  return path
    .split(".")
    .reduce<unknown>((current, key) => {
      if (current !== null && typeof current === "object") {
        return (current as Record<string, unknown>)[key];
      }
      return undefined;
    }, data);
}

/**
 * Renders a template string by replacing {{variable}} and
 * {{object.nested.path}} placeholders with values from `data`.
 *
 * Supported placeholder forms:
 *   {{name}}           – top-level property
 *   {{user.address}}   – dot-notation nested property
 *
 * Unknown placeholders are replaced with an empty string.
 */
export function renderTemplate(
  template: string,
  data: Record<string, unknown>
): string {
  return template.replace(/\{\{\s*([\w.]+)\s*\}\}/g, (_match, path: string) => {
    const value = resolvePath(data, path.trim());
    if (value === undefined || value === null) {
      return "";
    }
    return String(value);
  });
}

// ── Routes ────────────────────────────────────────────────────────────────────

app.get("/", (c) => {
  const template = `
    <html>
      <body>
        <h1>Hello, {{ name }}!</h1>
        <p>Email: {{ user.email }}</p>
        <p>Role:  {{ user.role }}</p>
      </body>
    </html>
  `;

  const data = {
    name: "Alice",
    user: {
      email: "alice@example.com",
      role: "admin",
    },
  };

  const html = renderTemplate(template, data);
  return c.html(html);
});

app.post("/render", async (c) => {
  // Expects JSON body: { template: string, data: object }
  const body = await c.req.json<{
    template: string;
    data: Record<string, unknown>;
  }>();

  const rendered = renderTemplate(body.template, body.data);
  return c.text(rendered);
});

export default app;
```

**Key design decisions:**

| Decision | Reason |
|---|---|
| `regex` + `resolvePath` instead of `eval()` | Prevents CWE-94 remote code execution |
| Dot-notation support (`user.email`) | Covers the most common "expression" need safely |
| `String(value)` coercion | Safely converts numbers/booleans to strings |
| Unknown placeholders → `""` | Predictable, no leaking of raw template syntax |

**If you need more expression power** (conditionals, loops, etc.) consider established safe libraries like **Mustache.js** or **Handlebars**, which are purpose-built to handle logic without `eval()`.

