import { Hono } from "hono";

const app = new Hono();

/**
 * Resolves a dot-notation path against a data object.
 * e.g. "user.name" → data.user.name
 */
function resolvePath(path: string, data: Record<string, unknown>): unknown {
  return path
    .trim()
    .split(".")
    .reduce<unknown>((current, key) => {
      if (current !== null && typeof current === "object") {
        return (current as Record<string, unknown>)[key];
      }
      return undefined;
    }, data);
}

/**
 * Renders a template string by replacing {{expression}} placeholders.
 *
 * Supported placeholder forms:
 *   {{variable}}           – simple variable lookup
 *   {{object.nested.key}}  – dot-notation path lookup
 *   {{variable ?? fallback}} – nullish-coalescing with a literal fallback
 *
 * Unknown variables are replaced with an empty string.
 */
export function renderTemplate(
  template: string,
  data: Record<string, unknown>
): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match, rawExpr: string) => {
    const expr = rawExpr.trim();

    // Support a simple nullish-coalescing fallback:  key ?? "default"
    const nullishIndex = expr.indexOf("??");
    if (nullishIndex !== -1) {
      const keyPart = expr.slice(0, nullishIndex).trim();
      const fallbackPart = expr
        .slice(nullishIndex + 2)
        .trim()
        // strip optional surrounding quotes from the fallback literal
        .replace(/^['"]|['"]$/g, "");

      const resolved = resolvePath(keyPart, data);
      return resolved != null ? String(resolved) : fallbackPart;
    }

    // Plain variable / dot-notation path
    const resolved = resolvePath(expr, data);
    return resolved != null ? String(resolved) : "";
  });
}

